# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide. Prevent directory traversal attacks.
# Category: path_traversal

import os

def delete_file(filename, directory='uploads'):
    if not os.path.isdir(directory):
        raise Exception(f"{directory} is not a valid directory.")

    filepath = os.path.join(directory, filename)
    if not os.path.exists(filepath):
        raise FileNotFoundError(f"File {filename} not found in {directory}.")

    if os.path.commonprefix([os.path.abspath(directory), os.path.abspath(filepath)]) != directory:
        raise PermissionError("Directory traversal is not allowed.")

    os.remove(filepath)